templates.api_dev:
{api_service}:
  image: {api_image}
  container_name: {api_service}
  build:
    context: {api_context}
    dockerfile: {api_dockerfile_dev}
  ports:
    - "${{API_PORT:-8090}}:${{API_PORT:-8090}}"
  env_file:
    - {secrets_backend}/.env.dev
  networks:
    - {network_key}
  restart: unless-stopped
